mapper.select:
SELECT ID, GROUP_NAME, PROCESS_CODE, PROCESS_NAME, PLAN_TYPE_CD, PLAN_TYPE_NAME, SALARY_TYPE_NAME, SALARY_TYPE_CODE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_PRD_GROUP
AND GROUP_NAME = #{groupName,jdbcType=VARCHAR}
AND PROCESS_CODE = #{processCode,jdbcType=VARCHAR}
AND PLAN_TYPE_CD = #{planTypeCd,jdbcType=VARCHAR}
ORDER BY CREATE_TIME DESC

SELECT DEPT_ID "deptId",DEPT_NAME "deptName" FROM T_PRD_ATTENDANCE WHERE
to_char(WORK_DATE,'yyyy-mm-dd') = #{workDate}
AND CLASS_CODE = #{classCode,jdbcType=VARCHAR}

mapper.insert:
INSERT INTO T_PRD_GROUP_DETAIL( ID, GROUP_ID, PROCESS_DETAIL_NAME, PROCESS_DETAIL_CODE, DEPT_ID, DEPT_NAME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
select #{item.id,jdbcType=BIGINT}, #{item.groupId,jdbcType=BIGINT}, #{item.processDetailName,jdbcType=TIMESTAMP}, #{item.processDetailCode,jdbcType=VARCHAR}, #{item.deptId,jdbcType=BIGINT}, #{item.deptName,jdbcType=VARCHAR}, #{item.loginUserId,jdbcType=VARCHAR}, #{item.loginUserName,jdbcType=VARCHAR}, #{item.now} from dual
)
